// Synthetics heartbeat canary.
// Runtime: syn-nodejs-puppeteer-X.Y
// Loads a target URL with a headless browser and asserts a 2xx response.

const synthetics = require('Synthetics');
const log = require('SyntheticsLogger');

const TARGET_URL = process.env.TARGET_URL || 'https://aws.amazon.com/';

const heartbeat = async function () {
  const page = await synthetics.getPage();

  // Synthetics will record HAR + screenshots automatically when we use executeStep.
  await synthetics.executeStep('loadHomepage', async function () {
    const response = await page.goto(TARGET_URL, {
      waitUntil: 'domcontentloaded',
      timeout: 30000,
    });

    if (!response) {
      throw new Error(`Failed to load ${TARGET_URL}: no response`);
    }
    const status = response.status();
    log.info(`GET ${TARGET_URL} -> ${status}`);
    if (status < 200 || status > 299) {
      throw new Error(`Unexpected status code ${status} for ${TARGET_URL}`);
    }
  });

  await synthetics.takeScreenshot('homepage', 'loaded');
};

exports.handler = async () => {
  return await heartbeat();
};
